solution:
def longest_cap(nums, target):
    left = 0
    s = 0
    best = 0
    for right in range(len(nums)):
        s += nums[right]
        while s > target:
            s -= nums[left]
            left += 1
        if right - left + 1 > best:
            best = right - left + 1
    return best

