def min_subarray_len(nums, target):
    left = 0
    s = 0
    best = 0
    for right in range(len(nums)):
        s += nums[right]
        while s >= target:
            length = right - left + 1
            if best == 0 or length < best:
                best = length
            s -= nums[left]
            left += 1
    return best

