    # your code here
    pass

solution:
from collections import Counter

def find_anagrams(s, p):
    k = len(p)
    if k > len(s):
        return []
    need = Counter(p)
    window = Counter(s[:k])
    res = []
    if window == need:
        res.append(0)
    for i in range(k, len(s)):
        window[s[i]] += 1
        window[s[i - k]] -= 1
        if window[s[i - k]] == 0:
            del window[s[i - k]]
        if window == need:
            res.append(i - k + 1)
    return res

