solution:
def min_window(s, t):
    if not t or not s:
        return ""
    need = {}
    for i in range(len(t)):
        c = t[i]
        need[c] = need.get(c, 0) + 1
    missing = len(t)
    left = 0
    best_l = 0
    best_len = 0
    for right in range(len(s)):
        c = s[right]
        if need.get(c, 0) > 0:
            missing -= 1
        need[c] = need.get(c, 0) - 1
        while missing == 0:
            if best_len == 0 or right - left + 1 < best_len:
                best_len = right - left + 1
                best_l = left
            need[s[left]] += 1
            if need[s[left]] > 0:
                missing += 1
            left += 1
    return s[best_l:best_l + best_len]
